  public static final String SELECT_BOE_DATA = "SELECT BP.BOE_PAYMENT_BP_BOE_NO AS BOE_PAYMENT_BP_BOE_NO, TO_CHAR(BP.BOE_PAYMENT_BP_BOE_DT,'DD/MM/YYYY') AS BOE_PAYMENT_BP_BOE_DT, BP.PORT_CODE AS PORT_CODE, BP.BOE_TRANS_TYPE AS BOE_TRANS_TYPE, EB.PD_CIF_NAME AS PD_CIF_NAME, EB.PD_CIF_ID AS PD_CIF_ID, BP.IECODE AS IE_CODE, BP.ADCODE AS AD_CODE, BP.CHANGED_IE_CODE AS CHANGED_IE_CODE, BP.IE_ADDRESS AS IE_ADDRESS, BP.IE_PAN AS IE_PAN, EB.BENEF_NAME AS BENEF_NAME, EB.BENEF_COUNTRY AS BENEF_COUNTRY, BP.BOE_PAYMENT_BP_BOE_CCY AS BOE_PAYMENT_BP_BOE_CCY, NVL(TRIM(BP.BOE_ENTRY_AMT), '0') AS BOE_ENTRY_AMT, BP.BOE_PAYMENT_BP_PAY_REF AS BOE_PAYMENT_BP_PAY_REF, BP.BOE_PAYMENT_BP_PAY_PART_REF AS BOE_PAYMENT_BP_PAY_PART_REF, NVL(TRIM(BP.BOE_PAYMENT_BP_PAY_FC_AMT), '0') AS BOE_PAYMENT_BP_PAY_FC_AMT, NVL(TRIM(EB.PD_OUTSTANDING_AMT), '0') AS PD_OUTSTANDING_AMT, TO_CHAR(EB.PD_TXN_DT,'DD/MM/YYYY') AS PD_TXN_DT, EB.PD_TXN_CCY AS PD_TXN_CCY, BP.EXCHANGE_RATE AS EXCHANGE_RATE, NVL(TRIM(BP.BOE_PAYMENT_BP_PAY_FULL_YN),' ') AS BOE_PAYMENT_BP_PAY_FULL_YN, NVL(TRIM(BP.BOE_PAYMENT_BP_PAY_ENDORSE_AMT), '0') AS BOE_PAYMENT_BP_PAY_ENDORSE_AMT, NVL(TRIM(BP.BOE_IGMNUMBER),'') AS BOE_IGMNUMBER, TO_CHAR(BP.BOE_IGMDATE,'DD/MM/YYYY') AS BOE_IGMDATE, NVL(TRIM(BP.BOE_HAWB_HBLNUMBER),'') AS BOE_HAWB_HBLNUMBER, TO_CHAR(BP.BOE_HAWB_HBLDATE,'DD/MM/YYYY') AS BOE_HAWB_HBLDATE, NVL(TRIM(BP.BOE_MAWB_MBLNUMBER),'') AS BOE_MAWB_MBLNUMBER, TO_CHAR(BP.BOE_MAWB_MBLDATE,'DD/MM/YYYY') AS BOE_MAWB_MBLDATE, DECODE(BP.IMPORT_AGENCY, 1, 'Customs', 'SEZ') AS IMPORT_AGENCY, BP.PORT_OF_SHIPMENT AS PORT_OF_SHIPMENT, BP.G_P AS G_P, DECODE(BP.BES_IND, 1, 'NEW', 3, 'CANCEL') AS BES_IND, DECODE(BP.RECORD_INDICATOR, 1, 'New', 2, 'Amendment', 3, 'Cancel') AS RECORD_INDICATOR, BP.REMARKS AS REMARKS, BP.PRE_ENDORSED_AMT AS PRE_ENDORSED_AMT FROM ETT_BOE_PAYMENT BP, ETTV_BOE_PAYMENT_DETAILS EB WHERE EB.PD_TXN_REF = BP.BOE_PAYMENT_BP_PAY_REF AND EB.PD_PART_PAY_REF = BP.BOE_PAYMENT_BP_PAY_PART_REF AND BP.BOE_PAYMENT_BP_BOE_NO = ? AND TO_CHAR(BP.BOE_PAYMENT_BP_BOE_DT,'DD/MM/YYYY') = ? AND BP.PORT_CODE = ? AND BP.BOE_PAYMENT_BP_PAY_REF = ? AND BP.BOE_PAYMENT_BP_PAY_PART_REF = ? AND BP.STATUS = 'P'";
